#[derive(Debug, Clone, Copy, serde::Serialize)]
pub enum PairQuality {
    Direct,
    Close,
    Userspace,
    Partial,
    Blocked,
    NotNeeded,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct SyscallMapping {
    pub nt_name: &'static str,
    pub xnu_name: &'static str,
    pub xnu_syscall: &'static str,
    pub quality: PairQuality,
    pub wine_impl: &'static str,
    pub category: &'static str,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct StructMapping {
    pub nt_name: &'static str,
    pub xnu_name: &'static str,
    pub quality: PairQuality,
    pub notes: &'static str,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct ObjectTypeMapping {
    pub nt_type: &'static str,
    pub creator: &'static str,
    pub xnu_mechanism: &'static str,
    pub wine_impl: &'static str,
    pub quality: PairQuality,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct ExecutiveFunctionMapping {
    pub category: &'static str,
    pub nt_prefix: &'static str,
    pub total_functions: usize,
    pub mapped: usize,
    pub quality: PairQuality,
    pub notes: &'static str,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct EndpointSecurityMapping {
    pub es_event: &'static str,
    pub nt_callback: &'static str,
    pub available_for_wine: bool,
    pub notes: &'static str,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct CoverageReport {
    pub total: usize,
    pub direct: usize,
    pub close: usize,
    pub userspace: usize,
    pub partial: usize,
    pub blocked: usize,
    pub not_needed: usize,
}

#[derive(Debug, Clone, serde::Serialize)]
pub struct DrillTarget {
    pub id: &'static str,
    pub description: &'static str,
    pub affected_anticheat: &'static [&'static str],
    pub approach: &'static str,
    pub roadmap_phase: &'static str,
}

