pub fn executive_function_table() -> Vec<ExecutiveFunctionMapping> {
    vec![
        ExecutiveFunctionMapping { category: "Memory Manager", nt_prefix: "MmXxx", total_functions: 85, mapped: 3, quality: PairQuality::Blocked, notes: "Most MmXxx are kernel-mode only (IOMemoryDescriptor). Userspace: mprotect, mach_vm_read/write for MmCopyMemory, mach_vm_region for MmIsAddressValid." },
        ExecutiveFunctionMapping { category: "Process/Thread", nt_prefix: "PsXxx", total_functions: 66, mapped: 18, quality: PairQuality::Partial, notes: "Core PsGetCurrent* and PsCreateSystemThread have direct XNU pairs. Anti-cheat critical: PsSetCreateProcessNotifyRoutineEx2, PsSetLoadImageNotifyRoutineEx need EndpointSecurity. PsSetCreateThreadNotifyRoutineEx has no XNU equivalent." },
        ExecutiveFunctionMapping { category: "I/O Manager", nt_prefix: "IoXxx", total_functions: 174, mapped: 12, quality: PairQuality::Blocked, notes: "IRP model has no XNU equivalent. Some IoCreateFile/IoDeviceIoControlFile map to open/ioctl. IoCreateNotificationEvent -> kqueue+EVFILT_USER. Most are kernel-only." },
        ExecutiveFunctionMapping { category: "Object Manager", nt_prefix: "ObXxx", total_functions: 15, mapped: 8, quality: PairQuality::Partial, notes: "ObCloseHandle -> close/mach_port_deallocate. ObRegisterCallbacks is anti-cheat critical -- needs MACF or EndpointSecurity. Others are Wine handle table operations." },
        ExecutiveFunctionMapping { category: "Security", nt_prefix: "SeXxx", total_functions: 7, mapped: 5, quality: PairQuality::Close, notes: "SeAccessCheck -> access()/mac_vnode_check_access. SeSinglePrivilegeCheck -> mac_priv_check. Others are Wine-internal SECURITY_DESCRIPTOR management." },
        ExecutiveFunctionMapping { category: "Configuration", nt_prefix: "CmXxx", total_functions: 9, mapped: 6, quality: PairQuality::Blocked, notes: "CmRegisterCallback has no macOS equivalent -- no registry notification. CmUnRegisterCallback and others are Wine stubs." },
        ExecutiveFunctionMapping { category: "Executive Library", nt_prefix: "ExXxx", total_functions: 104, mapped: 25, quality: PairQuality::Close, notes: "ExAllocatePool -> malloc. ExInitializeFastMutex/PushLock -> os_unfair_lock. ExInitializeResourceLite -> pthread_rwlock. ExUuidCreate -> uuid_generate. ExXxxTimer -> mk_timer." },
        ExecutiveFunctionMapping { category: "Core Kernel", nt_prefix: "KeXxx", total_functions: 60, mapped: 22, quality: PairQuality::Close, notes: "KeInitializeSpinLock -> os_unfair_lock. KeInitializeEvent/Mutex/Semaphore/Timer have direct XNU pairs. KeWaitForSingleObject -> ulock_wait/kevent. KeMemoryBarrier -> __sync_synchronize. KeBugCheck -> panic_with_data (kernel only)." },
        ExecutiveFunctionMapping { category: "Run-Time Library", nt_prefix: "RtlXxx", total_functions: 300, mapped: 20, quality: PairQuality::Direct, notes: "RtlCopyMemory -> memcpy, RtlMoveMemory -> memmove, RtlZeroMemory -> bzero. RtlSecureZeroMemory -> explicit_bzero. RtlStringFromGUID -> uuid_unparse. ~280 remaining are pure userspace computation." },
        ExecutiveFunctionMapping { category: "Power Manager", nt_prefix: "PoXxx", total_functions: 57, mapped: 0, quality: PairQuality::Blocked, notes: "All 57 PoXxx are kernel-mode only (IOPMPowerSource/RootDomain). Wine returns STATUS_SUCCESS for all. Not anti-cheat relevant." },
        ExecutiveFunctionMapping { category: "HAL", nt_prefix: "HalXxx", total_functions: 24, mapped: 0, quality: PairQuality::Blocked, notes: "All 24 HalXxx are kernel-mode only (Apple Silicon pexpert). Not relevant for Wine userspace." },
    ]
}

pub fn endpoint_security_table() -> Vec<EndpointSecurityMapping> {
    vec![
        EndpointSecurityMapping { es_event: "ES_EVENT_TYPE_NOTIFY_EXEC", nt_callback: "PsSetLoadImageNotifyRoutineEx", available_for_wine: true, notes: "Maps NT image load notification to macOS exec event. EndpointSecurity system extension can intercept all exec calls." },
        EndpointSecurityMapping { es_event: "ES_EVENT_TYPE_NOTIFY_FORK", nt_callback: "PsSetCreateProcessNotifyRoutineEx2", available_for_wine: true, notes: "Maps NT process creation notification to macOS fork. Can monitor child process creation for anti-cheat process tree validation." },
        EndpointSecurityMapping { es_event: "ES_EVENT_TYPE_NOTIFY_MMAP", nt_callback: "FltRegisterFilter (memory filter)", available_for_wine: true, notes: "Maps NT minifilter memory events to macOS mmap notifications. Can detect code injection and memory manipulation." },
        EndpointSecurityMapping { es_event: "ES_EVENT_TYPE_NOTIFY_SIGNAL", nt_callback: "Debug exception routing", available_for_wine: true, notes: "Maps NT debug exceptions to macOS signal delivery. Enables anti-debug detection and exception routing to Wine debugger." },
        EndpointSecurityMapping { es_event: "mac_proc_check_get_task", nt_callback: "ObRegisterCallbacks", available_for_wine: false, notes: "MACF policy for task port access control. Maps to NT handle callback registration. Requires kext -- not available as system extension." },
        EndpointSecurityMapping { es_event: "mac_vnode_check_signature", nt_callback: "Code integrity verification", available_for_wine: false, notes: "MACF policy for code signature checks. Maps to NT code integrity. Requires kext for full implementation. Partial via csops." },
        EndpointSecurityMapping { es_event: "mac_proc_check_syscall_unix", nt_callback: "Syscall filtering hook", available_for_wine: false, notes: "MACF policy for syscall interception. Could emulate NT kernel callback for syscall monitoring. Requires kext." },
        EndpointSecurityMapping { es_event: "task_set_exception_ports", nt_callback: "Kernel exception handler registration", available_for_wine: true, notes: "Mach exception port routing. Maps EXC_BAD_ACCESS -> EXCEPTION_ACCESS_VIOLATION, EXC_BREAKPOINT -> EXCEPTION_BREAKPOINT. Available from userspace via mach_msg." },
    ]
}

